"""Главное окно приложения."""from __future__ import annotationsimport refrom pathlib import Pathfrom typing import Anyfrom PySide6.QtCore import Qt, QThread, Signalfrom PySide6.QtGui import QActionfrom PySide6.QtWidgets import (    QFileDialog, QHBoxLayout, QMainWindow, QMessageBox, QProgressBar,    QPushButton, QScrollArea, QStatusBar, QTabWidget, QVBoxLayout, QWidget,)from ..core.pipeline import ExperimentPipelinefrom ..core.registry import Registryfrom ..core.types import ExperimentSeriesfrom ..export import (    export_docx,    export_series_xlsx,    export_session_xlsx,    export_single_xlsx,    export_txt,)from ..infrastructure.config import CONFIGfrom ..infrastructure.paths import EXPORTS_DIR, USER_MANUAL_HTMLfrom .widgets.comparison_tab import ComparisonTabfrom .widgets.filter_panel import FilterPanelfrom .widgets.help_dialog import HelpDialogfrom .widgets.noise_panel import NoisePanelfrom .widgets.plot_tab import PlotTabfrom .widgets.results_table_tab import ResultsTableTabfrom .widgets.run_panel import RunPanelfrom .widgets.signal_panel import SignalPanelfrom .widgets.text_output_tab import TextOutputTabfrom .workers.experiment_worker import ExperimentWorkerclass MainWindow(QMainWindow):    _run_requested = Signal(str, dict, str, dict, list, int, str)    def __init__(self, registry: Registry,                 pipeline: ExperimentPipeline) -> None:        super().__init__()        self._registry = registry        self._pipeline = pipeline        self._session_entries: list[Any] = []        self._help_dialog: HelpDialog | None = None        self.setWindowTitle("SAFR — анализ методов фильтрации сигналов")        self._signal_panel = SignalPanel(registry)        self._noise_panel = NoisePanel(registry)        self._filter_panel = FilterPanel(registry)        self._run_panel = RunPanel()        self._run_button = QPushButton("Запустить моделирование")        self._run_button.clicked.connect(self._on_run_clicked)        self._clear_button = QPushButton("Очистить результаты")        self._clear_button.clicked.connect(self._on_clear_results)        left_inner = QWidget()        left_inner_layout = QVBoxLayout(left_inner)        left_inner_layout.setContentsMargins(8, 8, 8, 8)        left_inner_layout.addWidget(self._signal_panel)        left_inner_layout.addWidget(self._noise_panel)        left_inner_layout.addWidget(self._filter_panel)        left_inner_layout.addWidget(self._run_panel)        left_inner_layout.addWidget(self._run_button)        left_inner_layout.addWidget(self._clear_button)        left_inner_layout.addStretch(1)        left_scroll = QScrollArea()        left_scroll.setWidget(left_inner)        left_scroll.setWidgetResizable(True)        left_scroll.setFrameShape(QScrollArea.NoFrame)        left_scroll.setMinimumWidth(440)        left_scroll.setMaximumWidth(560)        self._tabs = QTabWidget()        self._plot_tab = PlotTab()        self._text_tab = TextOutputTab()        self._table_tab = ResultsTableTab()        self._comparison_tab = ComparisonTab()        self._tabs.addTab(self._plot_tab, "Графики")        self._tabs.addTab(self._text_tab, "Текст")        self._tabs.addTab(self._table_tab, "Таблица")        self._tabs.addTab(self._comparison_tab, "Сравнение")        central = QWidget()        lay = QHBoxLayout(central)        lay.setContentsMargins(0, 0, 0, 0)        lay.addWidget(left_scroll, 0)        lay.addWidget(self._tabs, 1)        self.setCentralWidget(central)        self._build_menu()        sb = QStatusBar()        self._progress = QProgressBar()        self._progress.setRange(0, 0)        self._progress.setVisible(False)        self._progress.setMaximumWidth(160)        sb.addPermanentWidget(self._progress)        self.setStatusBar(sb)        self._set_status("Готово.")        self._thread = QThread(self)        self._worker = ExperimentWorker(self._pipeline)        self._worker.moveToThread(self._thread)        self._run_requested.connect(self._worker.run_series, Qt.QueuedConnection)        self._worker.finished.connect(self._on_finished)        self._worker.error.connect(self._on_error)        self._thread.start()    # ---------- меню ---------------------------------------------------------    def _build_menu(self) -> None:        menu_bar = self.menuBar()        file_menu = menu_bar.addMenu("&Файл")        self._act_export_last = QAction("Экспортировать последнюю серию…", self)        self._act_export_last.triggered.connect(self._on_export_last)        file_menu.addAction(self._act_export_last)        self._act_export_session = QAction("Экспортировать сессию (XLSX)…", self)        self._act_export_session.triggered.connect(self._on_export_session)        file_menu.addAction(self._act_export_session)        file_menu.addSeparator()        act_clear = QAction("Очистить результаты", self)        act_clear.triggered.connect(self._on_clear_results)        file_menu.addAction(act_clear)        file_menu.addSeparator()        act_exit = QAction("Выход", self)        act_exit.triggered.connect(self.close)        file_menu.addAction(act_exit)        help_menu = menu_bar.addMenu("&Справка")        act_manual = QAction("Открыть руководство пользователя", self)        act_manual.triggered.connect(self._on_open_manual)        help_menu.addAction(act_manual)        help_menu.addSeparator()        act_about = QAction("О программе", self)        act_about.triggered.connect(self._on_about)        help_menu.addAction(act_about)    # ---------- UI callbacks -------------------------------------------------    def _on_run_clicked(self) -> None:        try:            signal_name = self._signal_panel.selected_name()            signal_params = self._signal_panel.params()            noise_name = self._noise_panel.selected_name()            noise_params = self._noise_panel.params()            filter_specs = self._filter_panel.selected_filter_specs()            n_trials = self._run_panel.n_trials()            seed_mode = self._run_panel.seed_mode()        except Exception as e:            self._show_error(f"Ошибка чтения параметров: {e}")            return        if not filter_specs:            self._show_error(                "Не выбран ни один фильтр. "                "Отметьте хотя бы один фильтр галочкой."            )            return        self._run_button.setEnabled(False)        self._progress.setVisible(True)        self._set_status(            f"Идёт расчёт: {len(filter_specs)} фильтр(ов) × {n_trials} испытан."        )        self._run_requested.emit(            signal_name, signal_params,            noise_name, noise_params,            filter_specs, n_trials, seed_mode,        )    def _on_finished(self, payload: object) -> None:        if not isinstance(payload, ExperimentSeries):            self._on_error("Неожиданный тип результата расчёта")            return        series = payload        self._session_entries.append(series)        try:            # 1) Графики — плитка блоков (фильтр → 3 subplot, усреднение по N).            self._plot_tab.display_series(series)            # 2) Текстовая сводка + последний результат.            self._text_tab.display_series(series)            # 3) Таблица — добавляем новый узел верхнего уровня (эксперимент).            #    Уже существующие эксперименты остаются на месте.            self._table_tab.append_series(series)            # 4) Сравнительный столбчатый график обновляется под свежую серию.            self._comparison_tab.display_series(series)        except Exception as e:            self._show_error(f"Ошибка отображения результатов: {e}")        self._progress.setVisible(False)        self._run_button.setEnabled(True)        best_name = max(            series.filter_names,            key=lambda f: _nan_safe(series.aggregates[f].snr_improvement_db_mean),            default="—",        )        best = series.aggregates.get(best_name)        if best is not None:            self._set_status(                f"Готово. Экспериментов в сессии: {len(self._session_entries)}. "                f"Лучший ΔSNR (среднее): «{best_name}» = "                f"{best.snr_improvement_db_mean:+.2f} дБ "                f"(n={series.n_trials})"            )        else:            self._set_status(                f"Готово. Экспериментов в сессии: {len(self._session_entries)}."            )    def _on_error(self, message: str) -> None:        self._progress.setVisible(False)        self._run_button.setEnabled(True)        self._set_status(f"Ошибка: {message}")        self._show_error(message)    def _on_clear_results(self) -> None:        if not self._session_entries:            self._set_status("Сессия уже пуста.")            return        self._session_entries.clear()        self._table_tab.clear()        self._comparison_tab.clear()        self._plot_tab.clear()        self._text_tab.clear()        self._set_status("Результаты сессии очищены.")    # ---------- экспорт ------------------------------------------------------    def _on_export_last(self) -> None:        if not self._session_entries:            self._show_error(                "Нет данных для экспорта — выполните хотя бы один эксперимент."            )            return        series = self._session_entries[-1]        parent = QFileDialog.getExistingDirectory(            self, "Выберите каталог для отчёта", str(EXPORTS_DIR),        )        if not parent:            return        out_dir = Path(parent) / _series_slug(series)        try:            out_dir.mkdir(parents=True, exist_ok=True)            export_series_xlsx(series, out_dir / "series.xlsx")            last = series.last_result            if last is not None:                export_txt(last, out_dir / "report.txt")                export_single_xlsx(last, out_dir / "report.xlsx")                export_docx(last, out_dir / "report.docx")        except Exception as e:            self._show_error(f"Ошибка экспорта отчёта: {type(e).__name__}: {e}")            return        self._set_status(f"Отчёт сохранён: {out_dir}")    def _on_export_session(self) -> None:        if not self._session_entries:            self._show_error("Нет данных для экспорта.")            return        default = str(EXPORTS_DIR / "session.xlsx")        chosen, _filter = QFileDialog.getSaveFileName(            self, "Сохранить сессию", default, "Excel (*.xlsx)",        )        if not chosen:            return        if not chosen.lower().endswith(".xlsx"):            chosen += ".xlsx"        try:            export_session_xlsx(self._session_entries, chosen)        except Exception as e:            self._show_error(f"Ошибка экспорта сессии: {type(e).__name__}: {e}")            return        total_runs = sum(            s.total_runs if isinstance(s, ExperimentSeries) else 1            for s in self._session_entries        )        self._set_status(            f"Сессия сохранена: {chosen} (строк в Summary: {total_runs})"        )    # ---------- справка ------------------------------------------------------    def _on_open_manual(self) -> None:        try:            if self._help_dialog is None:                self._help_dialog = HelpDialog(USER_MANUAL_HTML, self)            self._help_dialog.show()            self._help_dialog.raise_()            self._help_dialog.activateWindow()        except Exception as e:            self._show_error(                f"Не удалось открыть руководство: {type(e).__name__}: {e}"            )    def _on_about(self) -> None:        QMessageBox.information(            self,            "О программе",            (                f"<b>{CONFIG.app_name}</b> — Signal Analysis &amp; Filtering Research<br>"                f"Версия: {CONFIG.version}<br><br>"                "Настольное приложение для исследования методов фильтрации шумов "                "и восстановления сигналов малой амплитуды."            ),        )    # ---------- utilities ----------------------------------------------------    def _show_error(self, message: str) -> None:        QMessageBox.critical(self, "SAFR", message)    def _set_status(self, text: str) -> None:        self.statusBar().showMessage(text)    def closeEvent(self, event) -> None:        self._thread.quit()        self._thread.wait(2000)        super().closeEvent(event)# ----------------------- helpers --------------------------------------------_SLUG_SAFE = re.compile(r"[^A-Za-z0-9А-Яа-я_\-]+")def _series_slug(series: ExperimentSeries) -> str:    ts = series.timestamp.replace(":", "-")    parts = [_slugify(series.signal_name), _slugify(series.noise_name)]    if len(series.filter_names) == 1:        parts.append(_slugify(series.filter_names[0]))    else:        parts.append(f"{len(series.filter_names)}filters")    parts.append(f"n{series.n_trials}")    return f"{ts}__" + "__".join(parts)def _slugify(s: str) -> str:    return _SLUG_SAFE.sub("_", s).strip("_")[:40] or "part"def _nan_safe(v: float) -> float:    try:        if v != v:            return float("-inf")    except Exception:        return float("-inf")    return v